import{_ as e,H as l,f as d,i as a}from"./chunks/framework.eFU6Tutu.js";const y=JSON.parse('{"title":"Популярные проблемы и решения","description":"","frontmatter":{},"headers":[],"relativePath":"care/problems.md","filePath":"care/problems.md"}'),n={name:"care/problems.md"};function s(r,t,g,i,x,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="популярные-проблемы-и-решения" tabindex="-1">Популярные проблемы и решения <a class="header-anchor" href="#популярные-проблемы-и-решения" aria-label="Permalink to &quot;Популярные проблемы и решения&quot;">​</a></h1><p>Самые частые проблемы, с которыми сталкиваются начинающие растениеводы, и способы их решения.</p><h2 id="общие-проблемы-для-всех-растении" tabindex="-1">Общие проблемы для всех растений <a class="header-anchor" href="#общие-проблемы-для-всех-растении" aria-label="Permalink to &quot;Общие проблемы для всех растений&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Проблема</th><th style="text-align:left;">Причина</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Желтеют листья</strong></td><td style="text-align:left;">Перелив, недостаток света, нехватка азота</td><td style="text-align:left;">Уменьшить полив, переставить на светлое окно, подкормить азотным удобрением</td></tr><tr><td style="text-align:left;"><strong>Сохнут кончики листьев</strong></td><td style="text-align:left;">Сухой воздух, жёсткая вода, перелив</td><td style="text-align:left;">Опрыскивать, использовать отстоянную воду, отрегулировать полив</td></tr><tr><td style="text-align:left;"><strong>Тонкие вытянутые побеги</strong></td><td style="text-align:left;">Мало света</td><td style="text-align:left;">Переставить на южное окно или включить фитолампу</td></tr><tr><td style="text-align:left;"><strong>Вянут и опускаются листья</strong></td><td style="text-align:left;">Перелив или пересушка, холодный сквозняк</td><td style="text-align:left;">Проверить влажность почвы, убрать от сквозняков, отрегулировать полив</td></tr><tr><td style="text-align:left;"><strong>Медленный рост</strong></td><td style="text-align:left;">Нехватка питания, тесный горшок, низкая температура</td><td style="text-align:left;">Подкормить, пересадить в更大的 горшок, повысить температуру</td></tr><tr><td style="text-align:left;"><strong>Белый налёт на листьях</strong></td><td style="text-align:left;">Мучнистая роса (грибок)</td><td style="text-align:left;">Обработать раствором соды (1 ч.л. на 1 л воды), проветривать, снизить влажность</td></tr><tr><td style="text-align:left;"><strong>Плесень на поверхности почвы</strong></td><td style="text-align:left;">Переувлажнение, плохая вентиляция</td><td style="text-align:left;">Снять верхний слой, прорыхлить, сократить полив, проветривать</td></tr></tbody></table><hr><h2 id="проблемы-с-зеленью-укроп-петрушка-салат-базилик" tabindex="-1">Проблемы с зеленью (укроп, петрушка, салат, базилик) <a class="header-anchor" href="#проблемы-с-зеленью-укроп-петрушка-салат-базилик" aria-label="Permalink to &quot;Проблемы с зеленью (укроп, петрушка, салат, базилик)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Проблема</th><th style="text-align:left;">Причина</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Семена долго не всходят</strong></td><td style="text-align:left;">Эфирные масла на оболочке (укроп, петрушка)</td><td style="text-align:left;">Замочить семена в тёплой воде на сутки, меняя воду</td></tr><tr><td style="text-align:left;"><strong>Листья мельчают и бледнеют</strong></td><td style="text-align:left;">Нехватка удобрений</td><td style="text-align:left;">Подкормить комплексным удобрением для зелени</td></tr><tr><td style="text-align:left;"><strong>Горький вкус (салат, укроп)</strong></td><td style="text-align:left;">Недостаток воды, слишком жарко</td><td style="text-align:left;">Поливать чаще, убрать от батареи, обеспечить прохладу</td></tr><tr><td style="text-align:left;"><strong>Коричневые пятна на листьях</strong></td><td style="text-align:left;">Грибок из-за переувлажнения</td><td style="text-align:left;">Уменьшить полив, проветривать, удалить больные листья</td></tr><tr><td style="text-align:left;"><strong>Салат уходит в стрелку (цветёт)</strong></td><td style="text-align:left;">Слишком жарко, длинный световой день (&gt;14 ч)</td><td style="text-align:left;">Обеспечить прохладу (18-20°C), сократить досветку</td></tr><tr><td style="text-align:left;"><strong>Базилик чернеет у основания</strong></td><td style="text-align:left;">«Чёрная ножка» (грибок от перелива)</td><td style="text-align:left;">Поливать умеренно, проветривать, поражённые растения удалить</td></tr></tbody></table><hr><h2 id="проблемы-с-овощами-помидоры-перцы-редис" tabindex="-1">Проблемы с овощами (помидоры, перцы, редис) <a class="header-anchor" href="#проблемы-с-овощами-помидоры-перцы-редис" aria-label="Permalink to &quot;Проблемы с овощами (помидоры, перцы, редис)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Проблема</th><th style="text-align:left;">Причина</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Растение цветёт, но нет завязей</strong></td><td style="text-align:left;">Недостаток света, высокая температура (&gt;30°C), нет опыления</td><td style="text-align:left;">Обеспечить 12-16 часов света, снизить температуру, встряхнуть куст для опыления</td></tr><tr><td style="text-align:left;"><strong>Опадают бутоны и завязи</strong></td><td style="text-align:left;">Недостаток света, перелив или пересушка, холод</td><td style="text-align:left;">Нормализовать свет, полив и температуру, подкормить калийно-фосфорным удобрением</td></tr><tr><td style="text-align:left;"><strong>Листья скручиваются лодочкой</strong></td><td style="text-align:left;">Перелив, холодный сквозняк, нехватка калия</td><td style="text-align:left;">Отрегулировать полив, убрать от сквозняков, подкормить золой</td></tr><tr><td style="text-align:left;"><strong>Фитофтора (бурые пятна на листьях)</strong></td><td style="text-align:left;">Избыток влаги, плохая вентиляция</td><td style="text-align:left;">Удалить больные листья, обработать Фитоспорином, сократить полив, проветривать</td></tr></tbody></table><h3 id="помидоры" tabindex="-1">Помидоры <a class="header-anchor" href="#помидоры" aria-label="Permalink to &quot;Помидоры&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Проблема</th><th style="text-align:left;">Причина</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Растение вытягивается, тонкий стебель</strong></td><td style="text-align:left;">Мало света</td><td style="text-align:left;">Добавить досветку (до 14-16 часов в сутки)</td></tr><tr><td style="text-align:left;"><strong>Плоды мелкие, бледные</strong></td><td style="text-align:left;">Нехватка питания, тесный горшок</td><td style="text-align:left;">Подкормить удобрением для томатов, пересадить в горшок большего объёма (от 8-10 л)</td></tr><tr><td style="text-align:left;"><strong>Вершинная гниль (тёмное пятно на плоде)</strong></td><td style="text-align:left;">Недостаток кальция, неравномерный полив</td><td style="text-align:left;">Подкормить кальциевой селитрой, поливать равномерно</td></tr></tbody></table><h3 id="перцы" tabindex="-1">Перцы <a class="header-anchor" href="#перцы" aria-label="Permalink to &quot;Перцы&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Проблема</th><th style="text-align:left;">Причина</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Сладкий перец стал горьким</strong></td><td style="text-align:left;">Переопыление с острым перцем</td><td style="text-align:left;">В следующий раз сажать отдельно, не рядом</td></tr><tr><td style="text-align:left;"><strong>Опадают цветки</strong></td><td style="text-align:left;">Недостаток света, жара, перелив или пересушка</td><td style="text-align:left;">Обеспечить 12-16 часов света, температуру +22-26°C, стабильный полив</td></tr><tr><td style="text-align:left;"><strong>Мелкие деформированные плоды</strong></td><td style="text-align:left;">Недостаток питания, тесный горшок</td><td style="text-align:left;">Подкормить удобрением для плодоношения, пересадить в горшок 3-5 л</td></tr></tbody></table><h3 id="редис" tabindex="-1">Редис <a class="header-anchor" href="#редис" aria-label="Permalink to &quot;Редис&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Проблема</th><th style="text-align:left;">Причина</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Не завязывается корнеплод (уходит в ботву)</strong></td><td style="text-align:left;">Слишком тепло (&gt;22°C), мало света, загущенные посадки</td><td style="text-align:left;">Обеспечить прохладу (+16-18°C), досветку, проредить</td></tr><tr><td style="text-align:left;"><strong>Уходит в стрелку (цветёт)</strong></td><td style="text-align:left;">Длинный световой день (&gt;14 часов), жара</td><td style="text-align:left;">Обеспечить режим освещения 10-12 часов, прохладу</td></tr><tr><td style="text-align:left;"><strong>Горький и деревянистый</strong></td><td style="text-align:left;">Пересушка почвы, передержан</td><td style="text-align:left;">Поливать регулярно, собирать вовремя</td></tr><tr><td style="text-align:left;"><strong>Пустотелый или «ватный» внутри</strong></td><td style="text-align:left;">Неравномерный полив, жарко</td><td style="text-align:left;">Поливать стабильно, обеспечить прохладу (+16-20°C)</td></tr><tr><td style="text-align:left;"><strong>Трескается</strong></td><td style="text-align:left;">Резкая смена полива: после засухи обильно</td><td style="text-align:left;">Поливать равномерно, не допускать пересыхания</td></tr></tbody></table><hr><h2 id="вредители" tabindex="-1">Вредители <a class="header-anchor" href="#вредители" aria-label="Permalink to &quot;Вредители&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Вредитель</th><th style="text-align:left;">Признаки</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Тля</strong></td><td style="text-align:left;">Мелкие зелёные или чёрные насекомые на молодых побегах и с нижней стороны листьев</td><td style="text-align:left;">Обработать мыльным раствором (1 ст. ложка жидкого мыла на 1 л воды) или настоем табачной пыли</td></tr><tr><td style="text-align:left;"><strong>Паутинный клещ</strong></td><td style="text-align:left;">Тонкая паутина на листьях и стеблях, листья желтеют и сохнут</td><td style="text-align:left;">Повысить влажность (опрыскивать), обработать Фитовермом или настоем чеснока</td></tr><tr><td style="text-align:left;"><strong>Белокрылка</strong></td><td style="text-align:left;">Мелкие белые бабочки, личинки на нижней стороне листьев</td><td style="text-align:left;">Развесить жёлтые клеевые ловушки, обработать биопрепаратами</td></tr><tr><td style="text-align:left;"><strong>Грибные комарики (сциариды)</strong></td><td style="text-align:left;">Мелкие чёрные мошки, личинки в почве</td><td style="text-align:left;">Сократить полив, посыпать поверхность земли слоем песка или керамзита</td></tr></tbody></table><hr><h2 id="как-предотвратить-проблемы" tabindex="-1">Как предотвратить проблемы <a class="header-anchor" href="#как-предотвратить-проблемы" aria-label="Permalink to &quot;Как предотвратить проблемы&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Действие</th><th style="text-align:left;">Эффект</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Правильный полив</strong> (не переливать и не пересушивать)</td><td style="text-align:left;">Предотвращает гниль корней, чёрную ножку и горечь</td></tr><tr><td style="text-align:left;"><strong>Достаточное освещение</strong> (12-16 часов, но не пересвечивать редис)</td><td style="text-align:left;">Предотвращает вытягивание, бледность и отсутствие плодов</td></tr><tr><td style="text-align:left;"><strong>Проветривание</strong> (но без сквозняков)</td><td style="text-align:left;">Снижает риск грибковых заболеваний</td></tr><tr><td style="text-align:left;"><strong>Чистота</strong> (удалять опавшие листья, не допускать плесени)</td><td style="text-align:left;">Уменьшает среду для вредителей и болезней</td></tr><tr><td style="text-align:left;"><strong>Качественный грунт</strong> (рыхлый, питательный, продезинфицированный)</td><td style="text-align:left;">Обеспечивает здоровый старт без патогенов</td></tr></tbody></table>',22)])])}const h=e(n,[["render",s]]);export{y as __pageData,h as default};
